"""
Secure command execution policy and validation.
Prevents shell injection by enforcing argv-only execution.
"""
import asyncio
import shlex
import logging
from typing import List, Optional, Dict, Any
from pathlib import Path
from dataclasses import dataclass
from datetime import datetime

logger = logging.getLogger(__name__)

@dataclass
class CommandAuditEntry:
    """Audit log entry for command execution"""
    timestamp: datetime
    command: List[str]
    cwd: str
    success: bool
    risk_level: str
    user_confirmed: bool = False
    error: Optional[str] = None

class CommandPolicy:
    """
    Central policy enforcement for secure command execution.
    All subprocess operations must go through this class.
    """

    # Shell metacharacters that are forbidden in arguments
    FORBIDDEN_METACHARS = {'&', '|', ';', '`', '$', '(', ')', '<', '>', '"', "'", '\\', '\n', '\r'}

    # Commands that are never allowed
    DANGEROUS_COMMANDS = {
        'rm', 'rmdir', 'del', 'deltree',
        'dd', 'fdisk', 'mkfs', 'format',
        'sudo', 'su', 'chmod', 'chown',
        'mv', 'move', 'cp', 'copy',  # Only allowed with explicit validation
        'curl', 'wget', 'nc', 'netcat',  # Network commands need special handling
        'eval', 'exec', 'source', '.',
    }

    # Default allowed commands (can be overridden by config)
    DEFAULT_ALLOWED_COMMANDS = {
        'git', 'ls', 'pwd', 'echo', 'cat', 'head', 'tail',
        'grep', 'find', 'which', 'python', 'python3', 'node', 'npm'
    }

    def __init__(self, allowed_commands: Optional[List[str]] = None):
        """
        Initialize command policy.

        Args:
            allowed_commands: List of allowed base commands. If None, uses defaults.
        """
        self.allowed_commands = set(allowed_commands or self.DEFAULT_ALLOWED_COMMANDS)
        self.audit_log: List[CommandAuditEntry] = []

    def validate_argv(self, argv: List[str]) -> bool:
        """
        Validate command arguments for security.

        Args:
            argv: Command arguments list

        Returns:
            True if command is safe to execute

        Raises:
            ValueError: If command is not allowed or contains forbidden characters
        """
        if not argv:
            raise ValueError("Empty command array")

        base_command = Path(argv[0]).name  # Get just the command name, not full path

        # Check if base command is in dangerous commands
        if base_command in self.DANGEROUS_COMMANDS:
            raise ValueError(f"Command '{base_command}' is forbidden for security reasons")

        # Check if base command is allowed
        if base_command not in self.allowed_commands:
            raise ValueError(f"Command '{base_command}' is not in allowed commands list")

        # Check all arguments for shell metacharacters
        for i, arg in enumerate(argv):
            if any(char in arg for char in self.FORBIDDEN_METACHARS):
                forbidden_chars = [char for char in self.FORBIDDEN_METACHARS if char in arg]
                raise ValueError(f"Argument {i} contains forbidden characters: {forbidden_chars}")

        return True

    def parse_command_safe(self, command_str: str) -> List[str]:
        """
        Safely parse a command string into argv list.

        Args:
            command_str: Command string to parse

        Returns:
            List of command arguments

        Raises:
            ValueError: If command contains shell injection attempts
        """
        try:
            # Use shlex to properly parse the command while respecting quotes
            argv = shlex.split(command_str, posix=True)
        except ValueError as e:
            raise ValueError(f"Invalid command syntax: {e}")

        # Additional validation
        self.validate_argv(argv)
        return argv

    async def execute_safe(self, argv: List[str], cwd: Optional[str] = None,
                          timeout: float = 30.0, risk_level: str = "LOW") -> Dict[str, Any]:
        """
        Execute command safely using subprocess_exec with full validation.

        Args:
            argv: Command arguments list
            cwd: Working directory (optional)
            timeout: Timeout in seconds
            risk_level: Risk level for audit logging

        Returns:
            Dict with 'success', 'stdout', 'stderr', 'returncode' keys
        """
        # Validate command first
        self.validate_argv(argv)

        # Set up execution parameters
        execution_cwd = cwd or str(Path.cwd())

        # Create audit entry
        audit_entry = CommandAuditEntry(
            timestamp=datetime.now(),
            command=argv.copy(),
            cwd=execution_cwd,
            success=False,
            risk_level=risk_level
        )

        try:
            # Execute using subprocess_exec (no shell)
            process = await asyncio.create_subprocess_exec(
                *argv,
                stdout=asyncio.subprocess.PIPE,
                stderr=asyncio.subprocess.PIPE,
                cwd=execution_cwd
            )

            try:
                stdout, stderr = await asyncio.wait_for(
                    process.communicate(),
                    timeout=timeout
                )

                result = {
                    'success': process.returncode == 0,
                    'stdout': stdout.decode('utf-8', errors='replace'),
                    'stderr': stderr.decode('utf-8', errors='replace'),
                    'returncode': process.returncode
                }

                audit_entry.success = result['success']
                if not result['success']:
                    audit_entry.error = result['stderr']

                logger.info(f"Command executed: {' '.join(argv)} -> {process.returncode}")

            except asyncio.TimeoutError:
                process.kill()
                await process.wait()
                result = {
                    'success': False,
                    'stdout': '',
                    'stderr': f'Command timed out after {timeout} seconds',
                    'returncode': -1
                }
                audit_entry.error = "Timeout"
                logger.warning(f"Command timed out: {' '.join(argv)}")

        except Exception as e:
            result = {
                'success': False,
                'stdout': '',
                'stderr': str(e),
                'returncode': -1
            }
            audit_entry.error = str(e)
            logger.error(f"Command execution failed: {' '.join(argv)} -> {e}")

        # Add to audit log
        self.audit_log.append(audit_entry)

        return result

    def get_audit_log(self, limit: Optional[int] = None) -> List[CommandAuditEntry]:
        """Get recent audit log entries."""
        if limit:
            return self.audit_log[-limit:]
        return self.audit_log.copy()

    def clear_audit_log(self):
        """Clear the audit log."""
        self.audit_log.clear()

# Global instance for use throughout the application
default_policy = CommandPolicy()